parallel -j 6 --dry-run --delay 15 --colsep , --header : CUDA_VISIBLE_DEVICES=3,4 'python src/dafm/main_optuna.py +experiment=Lorenz63Spantini2022 filter=EnsembleFlowFilter filter/prob_path={prob_path} filter/guidance=LocalConstant filter.sampling_time_step_count={sampling_time_step_count} filter.ensemble_size=20 setting.observe_every_n_time_steps={observe_every_n_time_steps} setting.reference_filter={reference_filter} "setting.observes=[{_target_:conf.observe.ObserveATan,order:0}]"' ::: sampling_time_step_count 5 10 20 : ::: $(duckdb runs.sqlite -c "copy (select alt_id as reference_filter, observe_every_n_time_steps from Conf join DataAssimilationSetting on Conf.DataAssimilationSetting = DataAssimilationSetting.id join filter_id_bpf using (Filter) join DataAssimilationSetting__Observe on DataAssimilationSetting.id = DataAssimilationSetting__Observe.DataAssimilationSetting join ObserveATan on DataAssimilationSetting__Observe.Observe = ObserveATan.id where save_ensemble_stats and observe_every_n_time_steps in (2, 4, 8) order by observe_every_n_time_steps) to '/dev/stdout';") ::: prob_path ConditionalOptimalTransport FilteringToPredictive
